import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"租车自驾攻略","description":"国外租车自驾的流程、保险和注意事项","frontmatter":{"title":"租车自驾攻略","description":"国外租车自驾的流程、保险和注意事项"},"headers":[],"relativePath":"knowledge/transportation/self-drive.md","filePath":"knowledge/transportation/self-drive.md","lastUpdated":null}'),i={name:"knowledge/transportation/self-drive.md"};function n(l,a,s,d,h,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="租车自驾攻略" tabindex="-1">租车自驾攻略 <a class="header-anchor" href="#租车自驾攻略" aria-label="Permalink to &quot;租车自驾攻略&quot;">​</a></h1><h2 id="租车流程" tabindex="-1">租车流程 <a class="header-anchor" href="#租车流程" aria-label="Permalink to &quot;租车流程&quot;">​</a></h2><p>通过租车平台（如租租车、Hertz、Avis）预订。取车时需提供护照、驾照原件和翻译件以及信用卡。</p><h2 id="保险选择" tabindex="-1">保险选择 <a class="header-anchor" href="#保险选择" aria-label="Permalink to &quot;保险选择&quot;">​</a></h2><p>基础保险通常不含第三者责任和车损。建议购买全险（超级补充险、玻璃轮胎险）以获得全面保障。</p><h2 id="驾驶规则" tabindex="-1">驾驶规则 <a class="header-anchor" href="#驾驶规则" aria-label="Permalink to &quot;驾驶规则&quot;">​</a></h2><p>靠右行驶的国家（如美国、欧洲大陆）和靠左行驶的国家（如日本、英国、澳大利亚）差异大。提前熟悉当地交规。</p><h2 id="停车指南" tabindex="-1">停车指南 <a class="header-anchor" href="#停车指南" aria-label="Permalink to &quot;停车指南&quot;">​</a></h2><p>市区停车费用高昂且车位紧张。使用停车APP查找和支付停车费更加便捷，注意禁停标志。</p>',9)])])}const f=e(i,[["render",n]]);export{_ as __pageData,f as default};
